SELECT AVG(property_avg_value) AS average_total_value
FROM resource_metrics
WHERE resource_id = 'MAIN' AND property_name = 'TOTAL';

SELECT resource_name
FROM resource
WHERE resource_status = 'active';

SELECT COUNT(*) AS active_resource_count
FROM resource
WHERE resource_status = 'active';

